def is_within_bounds(x, y, n, m):
    return 1 <= x <= n and 1 <= y <= m

def bfs(start_x, start_y, target_x, target_y, n, m):
    if start_x == target_x and start_y == target_y:
        return 0
    
    queue = deque([(start_x, start_y, 0)])
    visited = set()
    visited.add((start_x, start_y))
    
    moves = [(1, 2), (1, -2), (-1, 2), (-1, -2), (2, 1), (2, -1), (-2, 1), (-2, -1)]
    
    while queue:
        x, y, dist = queue.popleft()
        
        for dx, dy in moves:
            nx, ny = x + dx, y + dy
            if is_within_bounds(nx, ny, n, m) and (nx, ny) not in visited:
                if nx == target_x and ny == target_y:
                    return dist + 1
                visited.add((nx, ny))
                queue.append((nx, ny, dist + 1))
    
    return float('inf')

def choose_knight(n, m, x1, y1, x2, y2):
    white_target_x, white_target_y = n // 2, m // 2
    black_target_x, black_target_y = n // 2 + 1, m // 2
    
    # Distance for white knight to reach its target
    white_to_target = bfs(x1, y1, white_target_x, white_target_y, n, m)
    
    # Distance for black knight to reach its target
    black_to_target = bfs(x2, y2, black_target_x, black_target_y, n, m)
    
    # Distance for white knight to capture black knight
    white_to_black = bfs(x1, y1, x2, y2, n, m)
    
    # Distance for black knight to capture white knight
    black_to_white = bfs(x2, y2, x1, y1, n, m)
    
    # If Alice chooses WHITE, she moves first
    # If Alice chooses BLACK, Bob (with white) moves first
    
    # Calculate advantage for each choice
    # For white: Alice can reach target in white_to_target moves, Bob can interfere in black_to_white moves
    # For black: Bob reaches target in white_to_target moves, Alice can reach in black_to_target moves
    
    # Choose black if black has significantly better position
    # This accounts for the fact that if Alice chooses black, Bob goes first
    if black_to_target < white_to_target and black_to_white <= white_to_black:
        return "BLACK"
    else:
        return "WHITE"

